# Bad — no normalisation
Counter(["408", "408.0", " 408 ", "408"])  # Counter({'408': 2, '408.0': 1, ' 408 ': 1})

# Good — normalise first
def normalise(a):
    a = a.strip().lower()
    try:
        return str(int(float(a)))
    except ValueError:
        return a

Counter(normalise(a) for a in ["408", "408.0", " 408 ", "408"])
# Counter({'408': 4})
